// Digest hebdo -> canal jobs-alerts (récap + candidatures à relancer).
// Garde : si le webhook alerts n'est pas configuré, on ne poste rien.
if (!$env.DISCORD_WEBHOOK_ALERTS) return [];
const s = $input.first().json;
const relances = Array.isArray(s.relances) ? s.relances : JSON.parse(s.relances || '[]');
const lignes = [
  '📬 **Digest hebdo candidatures**',
  `Offres (7 j) : ${s.offres_7j} collectées · ${s.nouvelles_7j} à trier · ${s.postulees_7j} postulées · ${s.ignorees_7j} ignorées`,
  `Candidatures : ${s.cand_total} au total · ${s.reponses} réponse(s) · ${s.entretiens} entretien(s)`
];
if (relances.length) {
  lignes.push(`⏰ **À relancer** (${relances.length}) :`);
  for (const r of relances) lignes.push(`• ${r.poste || '?'} · ${r.entreprise || '?'} (postulé il y a ${r.jours} j)`);
} else {
  lignes.push('✅ Rien à relancer cette semaine.');
}
return [{ json: { content: lignes.join('\n').slice(0, 1900) } }];
